7115   // groups have the same size.
7116   auto IsEndOfGroupIndex = [=, &SortedOffsetsFromBase](unsigned Idx) {
7117     return SortedOffsetsFromBase[Idx] - SortedOffsetsFromBase[Idx - 1] !=
7118            StrideWithinGroup;
7119   };
